+import { $internal } from '../common';
+import type { Entity } from '../entity/types';
+import { getEntityId } from '../entity/utils/pack-entity';
+import { isRelation } from '../relation/utils/is-relation';
+import { getTrait, hasTrait } from '../trait/trait';
+import type { Trait } from '../trait/types';
+import { universe } from '../universe/universe';
+import type { World } from '../world';
+import { createModifier } from './modifier';
+import type { Predicate, PredicateValues, QueryInstance } from './types';
+import { createTrackingId } from './utils/tracking-cursor';
+import { checkQueryWithRelations } from './utils/check-query-with-relations';
+
+/** Creates a value-based query filter. Predicate dependencies must be data traits. */
+export function createPredicate<T extends Trait[]>(
+    dependencies: T,
+    predicate: (values: PredicateValues<T>) => boolean
+): Predicate<T> {
+    for (const dependency of dependencies) {
+        if (isRelation(dependency) || dependency[$internal].relation) {
+            throw new Error('Predicate dependencies cannot be relations.');
+        }
+        if (dependency[$internal].type === 'tag') {
+            throw new Error('Predicate dependencies cannot be tags.');
+        }
+    }
+
+    const filter = createModifier('predicate', createTrackingId(), dependencies) as Predicate<T>;
+    filter.predicate = predicate;
+    filter.initialStates = new Map();
+
+    for (const world of universe.worlds) {
+        if (world) filter.initialStates.set(world, snapshotPredicate(world, filter));
+    }
+
+    return filter;
+}
+
+export function evaluatePredicate(world: World, entity: Entity, predicate: Predicate): boolean {
+    const values: unknown[] = [];
+    for (const dependency of predicate.traits) {
+        if (!hasTrait(world, entity, dependency)) return false;
+        values.push(getTrait(world, entity, dependency));
+    }
+    return predicate.predicate(values as PredicateValues<Trait[]>);
+}
+
+function snapshotPredicate(world: World, predicate: Predicate): boolean[] {
+    const states: boolean[] = [];
+    for (const entity of world.entities) states[getEntityId(entity)] = evaluatePredicate(world, entity, predicate);
+    return states;
+}
+
+export function matchesPredicates(world: World, query: QueryInstance, entity: Entity): boolean {
+    let hasOr = false;
+    let anyOr = false;
+    for (const filter of query.predicates) {
+        const matches = evaluatePredicate(world, entity, filter.predicate);
+        if (filter.mode === 'required' && !matches) return false;
+        if (filter.mode === 'forbidden' && matches) return false;
+        if (filter.mode === 'or') {
+            hasOr = true;
+            anyOr ||= matches;
+        }
+    }
+    return !hasOr || anyOr;
+}
+
+/** Re-evaluate all predicates affected by a dependency mutation. */
+export function refreshPredicateQueries(world: World, entity: Entity, trait: Trait) {
+    const instance = world[$internal].traitInstances[trait.id];
+    if (!instance) return;
+
+    for (const query of instance.predicateQueries) {
+        let transitionMatches = query.trackingPredicates.length === 0;
+        for (const tracking of query.trackingPredicates) {
+            const states = query.predicateStates.get(tracking.predicate)!;
+            const eid = getEntityId(entity);
+            const previous = states[eid] || false;
+            const current = evaluatePredicate(world, entity, tracking.predicate);
+            states[eid] = current;
+            const matches =
+                tracking.type === 'add'
+                    ? !previous && current
+                    : tracking.type === 'remove'
+                      ? previous && !current
+                      : previous !== current;
+            transitionMatches &&= matches;
+        }
+
+        const staticMatches = checkQueryWithRelations(world, query, entity);
+        if (staticMatches && transitionMatches) query.add(entity);
+        else query.remove(world, entity);
+    }
+}
