+describe('predicates', () => {
+    const Position = trait({ x: 0 });
+
+    it('filters data traits and refreshes on add and set', () => {
+        const world = createWorld();
+        const Positive = createPredicate([Position], ([position]) => position.x > 0);
+        const entity = world.spawn(Position({ x: -1 }));
+
+        expect(world.query(Positive)).toEqual([]);
+        entity.set(Position, { x: 1 });
+        expect(world.query(Positive)).toEqual([entity]);
+    });
+
+    it('supports Not, Or, and relation pairs without adding predicate data to callbacks', () => {
+        const world = createWorld();
+        const Parent = relation();
+        const Positive = createPredicate([Position], ([position]) => position.x > 0);
+        const parent = world.spawn();
+        const matching = world.spawn(Position({ x: 1 }), Parent(parent));
+        world.spawn(Position({ x: -1 }), Parent(parent));
+
+        expect(world.query(Not(Positive))).toHaveLength(2); // Includes the parent with no Position.
+        expect(world.query(Or(Positive), Parent(parent))).toEqual([matching]);
+        world.query(Positive, Position).readEach((state) => expect(state).toHaveLength(1));
+    });
+
+    it('tracks predicate truthiness transitions', () => {
+        const world = createWorld();
+        const Positive = createPredicate([Position], ([position]) => position.x > 0);
+        const Added = createAdded();
+        const Removed = createRemoved();
+        const Changed = createChanged();
+        const entity = world.spawn(Position({ x: -1 }));
+        world.query(Added(Positive));
+        world.query(Removed(Positive));
+        world.query(Changed(Positive));
+
+        entity.set(Position, { x: 1 });
+        expect(world.query(Added(Positive))).toEqual([entity]);
+        expect(world.query(Changed(Positive))).toEqual([entity]);
+        expect(world.query(Removed(Positive))).toEqual([]);
+
+        entity.set(Position, { x: -1 });
+        expect(world.query(Removed(Positive))).toEqual([entity]);
+        expect(world.query(Changed(Positive))).toEqual([entity]);
+    });
+
+    it('rejects tags and relations as dependencies', () => {
+        expect(() => createPredicate([trait()], () => true)).toThrow();
+        expect(() => createPredicate([relation() as any], () => true)).toThrow();
+    });
+});
